    {"offset": {"line": 1004, "column": 0}, "map": {"version":3,"sources":["file:///E:/Hackthon/BGSCET/BGSCET/FarmBid/frontend/components/ui/avatar.jsx"],"sourcesContent":["\"use client\"\r\n\r\nimport * as React from \"react\"\r\nimport * as AvatarPrimitive from \"@radix-ui/react-avatar\"\r\n\r\nimport { cn } from \"@/lib/utils\"\r\n\r\nconst Avatar = React.forwardRef(({ className, ...props }, ref) => (\r\n  <AvatarPrimitive.Root\r\n    ref={ref}\r\n    className={cn(\"relative flex h-10 w-10 shrink-0 overflow-hidden rounded-full\", className)}\r\n    {...props} />\r\n))\r\nAvatar.displayName = AvatarPrimitive.Root.displayName\r\n\r\nconst AvatarImage = React.forwardRef(({ className, ...props }, ref) => (\r\n  <AvatarPrimitive.Image\r\n    ref={ref}\r\n    className={cn(\"aspect-square h-full w-full\", className)}\r\n    {...props} />\r\n))\r\nAvatarImage.displayName = AvatarPrimitive.Image.displayName\r\n\r\nconst AvatarFallback = React.forwardRef(({ className, ...props }, ref) => (\r\n  <AvatarPrimitive.Fallback\r\n    ref={ref}\r\n    className={cn(\r\n      \"flex h-full w-full items-center justify-center rounded-full bg-muted\",\r\n      className\r\n    )}\r\n    {...props} />\r\n))\r\nAvatarFallback.displayName = AvatarPrimitive.Fallback.displayName\r\n\r\nexport { Avatar, AvatarImage, AvatarFallback }\r\n"],"names":["Avatar","className","props","ref","displayName","AvatarImage","AvatarFallback"],"mappings":";;;;;;;;;AAEA;AACA;AAEA;AALA;;;;;AAOA,MAAMA,uBAAS,2KAAgB,MAAC,CAAC,EAAEC,SAAS,EAAE,GAAGC,OAAO,EAAEC,oBACxD,6LAAC,6KAAoB;QACnBA,KAAKA;QACLF,WAAW,IAAA,qHAAE,EAAC,iEAAiEA;QAC9E,GAAGC,KAAK;;;;;;;AAEbF,OAAOI,WAAW,GAAG,6KAAoB,CAACA,WAAW;AAErD,MAAMC,4BAAc,2KAAgB,OAAC,CAAC,EAAEJ,SAAS,EAAE,GAAGC,OAAO,EAAEC,oBAC7D,6LAAC,8KAAqB;QACpBA,KAAKA;QACLF,WAAW,IAAA,qHAAE,EAAC,+BAA+BA;QAC5C,GAAGC,KAAK;;;;;;;AAEbG,YAAYD,WAAW,GAAG,8KAAqB,CAACA,WAAW;AAE3D,MAAME,+BAAiB,2KAAgB,OAAC,CAAC,EAAEL,SAAS,EAAE,GAAGC,OAAO,EAAEC,oBAChE,6LAAC,iLAAwB;QACvBA,KAAKA;QACLF,WAAW,IAAA,qHAAE,EACX,wEACAA;QAED,GAAGC,KAAK;;;;;;;AAEbI,eAAeF,WAAW,GAAG,iLAAwB,CAACA,WAAW"}},
    {"offset": {"line": 1069, "column": 0}, "map": {"version":3,"sources":["file:///E:/Hackthon/BGSCET/BGSCET/FarmBid/frontend/components/ui/tooltip.jsx"],"sourcesContent":["\"use client\"\r\n\r\nimport * as React from \"react\"\r\nimport * as TooltipPrimitive from \"@radix-ui/react-tooltip\"\r\n\r\nimport { cn } from \"@/lib/utils\"\r\n\r\nconst TooltipProvider = TooltipPrimitive.Provider\r\n\r\nconst Tooltip = TooltipPrimitive.Root\r\n\r\nconst TooltipTrigger = TooltipPrimitive.Trigger\r\n\r\nconst TooltipContent = React.forwardRef(({ className, sideOffset = 4, ...props }, ref) => (\r\n  <TooltipPrimitive.Portal>\r\n    <TooltipPrimitive.Content\r\n      ref={ref}\r\n      sideOffset={sideOffset}\r\n      className={cn(\r\n        \"z-50 overflow-hidden rounded-md bg-primary px-3 py-1.5 text-xs text-primary-foreground animate-in fade-in-0 zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 origin-[--radix-tooltip-content-transform-origin]\",\r\n        className\r\n      )}\r\n      {...props} />\r\n  </TooltipPrimitive.Portal>\r\n))\r\nTooltipContent.displayName = TooltipPrimitive.Content.displayName\r\n\r\nexport { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider }\r\n"],"names":["TooltipProvider","Tooltip","TooltipTrigger","TooltipContent","className","sideOffset","props","ref","displayName"],"mappings":";;;;;;;;;;;AAEA;AACA;AAEA;AALA;;;;;AAOA,MAAMA,kBAAkB,kLAAyB;AAEjD,MAAMC,UAAU,8KAAqB;AAErC,MAAMC,iBAAiB,iLAAwB;AAE/C,MAAMC,+BAAiB,2KAAgB,MAAC,CAAC,EAAEC,SAAS,EAAEC,aAAa,CAAC,EAAE,GAAGC,OAAO,EAAEC,oBAChF,6LAAC,gLAAuB;kBACtB,cAAA,6LAAC,iLAAwB;YACvBA,KAAKA;YACLF,YAAYA;YACZD,WAAW,IAAA,qHAAE,EACX,uaACAA;YAED,GAAGE,KAAK;;;;;;;;;;;;AAGfH,eAAeK,WAAW,GAAG,iLAAwB,CAACA,WAAW"}},
